interface User {
  name: string;
}

interface Admin {
  role: string;
}

function checkAccess(person: User | Admin) {
  if ('name' in person) {
    console.log(`User: ${person.name}`);
  } else {
    console.log(`Admin: ${person.role}`);
  }
}

checkAccess({ name: 'Alice' }); // User: Alice
checkAccess({ role: 'SuperAdmin' }); // Admin: SuperAdmin

